function ProjectModal({ project, onClose }) {
  const hover = useCursorHover();
  useEffect(() => {
    document.body.style.overflow = 'hidden';
    return () => { document.body.style.overflow = ''; };
  }, []);
  useEffect(() => {
    const esc = e => { if(e.key==='Escape') onClose(); };
    window.addEventListener('keydown', esc);
    return () => window.removeEventListener('keydown', esc);
  }, [onClose]);
  return (
    <div className="pf-modal-backdrop" onClick={e => e.target===e.currentTarget && onClose()}>
      <div className="pf-modal">
        <button className="pf-modal-close" onClick={onClose} {...hover}>✕</button>
        <img className="pf-modal-img" src={project.img} alt={project.title}/>
        <div className="pf-modal-body">
          <div className="pf-modal-chips">
            {project.chips.map(c=><span key={c} className="pf-modal-chip">{c}</span>)}
          </div>
          <h2 className="pf-modal-title">{project.title}</h2>
          <p className="pf-modal-desc">{project.modalDesc}</p>
          <a href={project.figma} target="_blank" rel="noopener noreferrer" className="pf-modal-cta" {...hover}>
            View in Figma ↗
          </a>
        </div>
      </div>
    </div>
  );
}

